1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Step = { op: "quote"; items: Item[] };
3	export type Result = { premium: number };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
17	
18	const quotePremium = (items: Item[]): number => {
19	  const base = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
20	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
21	  return Math.ceil(base + firstInsuranceSurcharge + PROCESSING_FEE);
22	};
23	
24	export const runScenario = (input: {
25	  customer: { yearsWithMHPCO: number };
26	  steps: Step[];
27	}): { results: Result[] } => {
28	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
29	  return { results };
30	};
